Analyze Text.code:
// Ask the model to analyze a block of text.
// The chat completion is written to state.data.
prompt(
  `Analyze the following text and return the key themes, tone and any action items.\n\nTEXT:\n${JSON.stringify($.data.text)}`,
  {
    // Pick a chat-completions capable model.
    model: 'gpt-4o-mini',
    // Keep output deterministic for analysis tasks.
    temperature: 0.2,
  }
);

