Analyze Text Sentiment (Legacy).code:
// Return a sentiment label + score for a block of text.
prompt(
  `Rate the sentiment of the text below. Reply as JSON:\n{ "label": "positive" | "neutral" | "negative", "score": number between -1 and 1 }\n\nTEXT:\n${$.data.text}`,
  {
    model: 'gpt-4o-mini',
    temperature: 0,
    // Force the model to emit valid JSON.
    response_format: { type: 'json_object' },
  }
);

Extract Structured Data.code:
// Extract structured fields from unstructured text.
// The model is constrained to a JSON schema; result lands on state.data.
prompt(
  `Extract the contact details from the message below.\n\nMESSAGE:\n${$.data.message}`,
  {
    model: 'gpt-4o-mini',
    temperature: 0,
    response_format: {
      type: 'json_schema',
      json_schema: {
        name: 'contact',
        schema: {
          type: 'object',
          properties: {
            name:  { type: 'string' },
            email: { type: 'string' },
            phone: { type: 'string' },
          },
          required: ['name'],
          additionalProperties: false,
        },
      },
    },
  }
);

